// Determine which workflows to run based on current time
const now = new Date();
const minute = now.getMinutes();
const hour = now.getHours();

const toRun = [];

// EVERY 15 MIN: Stats Puller (always)
toRun.push({ workflow: '01 - Stats Puller', reason: 'Every 15 min' });

// EVERY 30 MIN (on :00 and :30): Smart Bidder, Remoderator
if (minute === 0 || minute === 30 || minute === 15 || minute === 45) {
  toRun.push({ workflow: '03 - Smart Bidder', reason: 'Every 30 min' });
  toRun.push({ workflow: '09 - Re-moderator', reason: 'Every 30 min' });
}

// EVERY HOUR (on :00): Balance, Image Factory, Uploader, Anomaly Detector
if (minute < 15) {
  toRun.push({ workflow: '02 - Balance Watchdog', reason: 'Every hour' });
  toRun.push({ workflow: '07 - Image Factory', reason: 'Every hour' });
  toRun.push({ workflow: '08 - Teaser Uploader', reason: 'Every hour' });
  toRun.push({ workflow: '12 - Anomaly Detector', reason: 'Every hour' });
}

// EVERY 2 HOURS (even hours): Budget Pacer, Trend Hunter, Position Scanner
if (hour % 2 === 0 && minute < 15) {
  toRun.push({ workflow: '05 - Budget Pacer', reason: 'Every 2 hours' });
  toRun.push({ workflow: '06 - Trend Hunter', reason: 'Every 2 hours' });
  toRun.push({ workflow: '15 - Position Scanner', reason: 'Every 2 hours' });
}

// EVERY 4 HOURS: AB Tester
if (hour % 4 === 0 && minute < 15) {
  toRun.push({ workflow: '10 - A/B Testing Engine', reason: 'Every 4 hours' });
}

return [{ json: { workflows: toRun, count: toRun.length, timestamp: $now.toISO() } }];

const data = $input.first().json;
const workflows = data.workflows || [];

return workflows.map(w => ({ json: w }));

// Morning routine: run startup sequence
const morningWorkflows = [
  '01 - Stats Puller',
  '02 - Balance Watchdog',
  '06 - Trend Hunter',
  '07 - Image Factory',
  '08 - Teaser Uploader',
  '09 - Re-moderator',
  '15 - Position Scanner'
];

return morningWorkflows.map(w => ({ json: { workflow: w, reason: 'Morning startup' } }));

const m = $input.first().json;

let msg = `🤖 MASTER ORCHESTRATOR - Morning Status\n`;
msg += `${$now.format('dd.MM.yyyy HH:mm')}\n\n`;
msg += `📊 System: OPERATIONAL\n`;
msg += `📈 Yesterday's recap:\n`;
msg += `  Stats entries: ${m.stats_today || 0}\n`;
msg += `  Balance checks: ${m.balance_checks_today || 0}\n`;
msg += `  Bid changes: ${m.bid_changes_today || 0}\n`;
msg += `  New teasers: ${m.new_teasers_today || 0}\n`;
msg += `  Anomalies: ${m.anomalies_today || 0}\n`;
msg += `  Balance: $${m.last_known_balance || 'N/A'}\n`;
msg += `  Active teasers (7d): ${m.active_teasers_week || 0}\n\n`;
msg += `⏰ Schedule: All 18 workflows connected\n`;
msg += `✅ Morning startup sequence launched`;

return [{ json: { message: msg } }];

// Evening wrap-up sequence
const eveningWorkflows = [
  '11 - Daily Report',
  '13 - Block Optimizer (Blacklist/Whitelist)',
  '04 - Geo Bid Optimizer',
  '16 - Spy Module (Competitive Intelligence)'
];

return eveningWorkflows.map(w => ({ json: { workflow: w, reason: 'Evening wrap-up' } }));

// Weekly optimization sequence
const weeklyWorkflows = [
  '14 - Coefficient Tuner (OS/Browser/ISP)',
  '18 - Time Targeting Optimizer'
];

return weeklyWorkflows.map(w => ({ json: { workflow: w, reason: 'Weekly optimization' } }));

// Log execution to track orchestrator activity
const workflow = $json.workflow || 'unknown';
const reason = $json.reason || 'scheduled';

return [{ json: {
  log: `[${$now.format('HH:mm:ss')}] Triggered: ${workflow} (${reason})`,
  workflow: workflow,
  status: 'triggered'
} }];
